using System;
using Unity.Cinemachine;
using UnityEngine;
public class Figures : MonoBehaviour { public event Action OnAttackStarted; public event Action OnFigureDestroyed; [SerializeField] public int _damageAmount = 25; [SerializeField] private int _damageAmountforBoss = 10; [SerializeField] private float _delay = 10f; [SerializeField] private float _speed = 10f; [SerializeField] private PolygonCollider2D _polygonCollider2D; private Transform target; private float _timer; private float _curveAmplitude = 3f; private float _curveFrequency = 1f; private float _lifeTime = 0f; private Rigidbody2D _rigidbody; private bool _isAttack = false; private bool _isEnd = false; private bool _activated = false; private bool _isRejected = false; [SerializeField] private AudioSource _audioSource; [SerializeField] private AudioClip HitClip; public bool IsAttackFinished { get; private set; } public void Activate() { _activated = true; _timer = _delay; OnAttackStarted?.Invoke(); } private void Start() { IsAttackFinished = false; _rigidbody = GetComponent<Rigidbody2D>(); GameObject player = GameObject.FindGameObjectWithTag("Player"); if (player != null) target = player.transform; _audioSource = gameObject.AddComponent<AudioSource>(); _audioSource.playOnAwake = false; _audioSource.volume = 0; } public void OnHit(Transform newTarget) { _isRejected = true; target = newTarget; _lifeTime = 0f; _isAttack = true; _activated = true; _timer = 5.0f; _polygonCollider2D.enabled = true; } public bool IsAttack() { return _isAttack; } public bool IsEnd() { return _isEnd; } public void AttackColliderTurnoff() { _polygonCollider2D.enabled = false; } private void Update() { if (!_activated) return; _timer -= Time.deltaTime; if (_timer <= 8.5f && !_isAttack) { _isAttack = true; } if (_timer <= 0.5f) { _isEnd = true; } if (_timer <= 0f && gameObject.activeSelf) { IsAttackFinished = true; OnFigureDestroyed?.Invoke(); gameObject.SetActive(false); } } private void FixedUpdate() { if (_isAttack) HomingLogic(); } private void HomingLogic() { if (target == null) return; _lifeTime += Time.fixedDeltaTime; Vector2 direction = (target.position - transform.position); direction.Normalize(); Vector2 perpendicular = new Vector2(-direction.y, direction.x); float curveOffset = Mathf.Sin(_lifeTime * _curveFrequency) * _curveAmplitude; Vector2 curvedDirection = (direction + perpendicular * curveOffset).normalized; _rigidbody.linearVelocity = curvedDirection * _speed; float horizontal = target.position.x - _rigidbody.position.x; float angle = horizontal >= 0 ? 0f : 180f; _rigidbody.rotation = angle; } private void OnTriggerStay2D(Collider2D collision) { if (collision.transform.TryGetComponent(out Reiko reiko)) { _audioSource.PlayOneShot(HitClip); AttackColliderTurnoff(); reiko.TakeDamage(_damageAmount); _timer = 0.5f; IsAttackFinished = true; } if (collision.transform.TryGetComponent(out Minori minori)) { _audioSource.PlayOneShot(HitClip); AttackColliderTurnoff(); minori.TakeDamage(_damageAmount); _timer = 0.5f; IsAttackFinished = true; } if (collision.CompareTag("Boss") && _isRejected == true) { _audioSource.PlayOneShot(HitClip); AttackColliderTurnoff(); BossEntity.Instance.TakeDamageBoss(_damageAmountforBoss); _timer = 0.5f; IsAttackFinished = true; } } }